function generateMandalaPattern(seed: number, depth: number): string[] {
  const symbols = ["◈", "◉", "◎", "◐"];
  const rows: string[] = [];

  for (let d = 0; d < 4; d++) {
    const width = 7 + d * 3;
    const row: string[] = [];

    for (let i = 0; i < width; i++) {
      const randomOffset = (seed + d * 31 + i * 17) % 100;
      const symbolIndex = (d + (randomOffset > 50 ? 1 : 0)) % 4;
      row.push(symbols[symbolIndex]!);
    }

    rows.push(row.join(" "));
  }

  return rows;
}

